mapper.select:
/* wms-ctmaster-strategymaster-sql-oracle.xml - selectStrategyMaster - 전략 마스터 조회 SQL */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT '0' AS CHK ,STGKEY ,STGDESC ,STGTYPE ,#{ctkey} || ';' || 'STGTYPE' || ';' || STGTYPE AS STGTYPE_DESC ,SYSTYPE ,#{ctkey} || ';' || 'STGSYSTYPE' || ';' || SYSTYPE AS SYSTYPE_DESC ,DFVAL ,RMK ,JAVABEANID ,USEYN ,#{ctkey} || ';' || 'YESORNO' || ';' || USEYN AS USEYN_DESC ,INSERTDATE ,INSERTURKEY ,UPDATEDATE ,UPDATEURKEY FROM TWORK_MST_STG
AND STGKEY = #{stgkey}
AND #{SEARCH_CONDITION}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY UPDATEDATE DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

/* wms-ctmaster-strategymaster-sql-oracle.xml - selectStrategyMasterCount - 전략 마스터 건수 조회  SQL */
	SELECT	COUNT(1)  
	  FROM	TWORK_MST_STG 


	 		STGKEY = #{stgkey}


		    #{SEARCH_CONDITION}

mapper.insert:

/* wms-ctmaster-strategymaster-sql-oracle.xml - insertTWorkMstStg - 전략 마스터 등록  SQL */
	INSERT INTO TWORK_MST_STG
			(
		    	STGKEY
		       ,STGDESC
		       ,STGTYPE
		       ,SYSTYPE
		       ,DFVAL
		       ,RMK
		       ,JAVABEANID
		       ,USEYN
		       ,INSERTDATE
		       ,INSERTURKEY
		       ,UPDATEDATE
		       ,UPDATEURKEY			      	
		    ) 
		    VALUES 
		    (
				#{stgkey}
				,#{stgdesc}
				,#{stgtype}
				,#{systype}
				,#{dfval}
				,#{rmk}
				,#{javabeanid}
				,#{useyn}
				,#{sysdate}
				,#{surkey}
				,#{sysdate}
				,#{surkey}
			)

mapper.update:
 	/* wms-ctmaster-strategymaster-sql-oracle.xml - updateTWorkMstStg - 전략 마스터 수정  SQL */
 		UPDATE	TWORK_MST_STG
 		   SET	UPDATEDATE  		= #{sysdate}
		        ,UPDATEURKEY 		= #{surkey}
			    ,STGDESC    		= #{stgdesc}
		        ,STGTYPE    		= #{stgtype}
		        ,SYSTYPE        	= #{systype}
		        ,DFVAL 				= #{dfval}
		        ,RMK 				= #{rmk}
		        ,JAVABEANID 		= #{javabeanid}
		        ,USEYN 				= #{useyn}
		 WHERE	STGKEY 				= #{stgkey}

mapper.delete:
 	/* wms-ctmaster-strategymaster-sql-oracle.xml - deleteTWorkMstStg - 전략 마스터 삭제  SQL */	
			DELETE 
			 FROM	TWORK_MST_STG
			WHERE	STGKEY = #{stgkey}
